import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.B_-t2C-M.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md"}'),l={name:"guide/changelog.md"};function r(s,e,n,c,d,u){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="v1-0-2-—-2026-03-13" tabindex="-1">v1.0.2 — 2026-03-13 <a class="header-anchor" href="#v1-0-2-—-2026-03-13" aria-label="Permalink to &quot;v1.0.2 — 2026-03-13&quot;">​</a></h2><h3 id="code-coverage" tabindex="-1">Code Coverage <a class="header-anchor" href="#code-coverage" aria-label="Permalink to &quot;Code Coverage&quot;">​</a></h3><ul><li>Achieved <strong>100% code coverage</strong> across all application classes (Controllers, Services, Models, Middleware, Requests, Resources, Observers, Policies, Notifications, Enums, Traits, Jobs, Events, Exceptions).</li></ul><h3 id="critical-business-logic-fixes" tabindex="-1">Critical Business Logic Fixes <a class="header-anchor" href="#critical-business-logic-fixes" aria-label="Permalink to &quot;Critical Business Logic Fixes&quot;">​</a></h3><ul><li><strong>BIZ-01</strong>: Stock is now deducted at checkout via <code>InventoryService::deduct()</code> for every cart item with <code>track_inventory</code> enabled. Prevents overselling.</li><li><strong>BIZ-02</strong>: Refund amount validation — <code>refundToOriginalPayment()</code> now rejects amounts &lt;= 0 and amounts exceeding the original payment.</li><li><strong>BIZ-03</strong>: Tax calculation integrated into checkout via <code>TaxService::calculate()</code> using the delivery address country/state.</li><li><strong>BIZ-04</strong>: Wallet <code>credit()</code> pessimistic lock fixed — now uses <code>Wallet::where()-&gt;lockForUpdate()-&gt;firstOrFail()</code>, aligned with <code>debit()</code>.</li><li><strong>BIZ-05</strong>: <code>InventoryService::deduct()</code> now throws <code>InsufficientStockException</code> if requested quantity exceeds available stock. Prevents negative inventory.</li><li><strong>BIZ-06</strong>: <code>buy_x_get_y</code> coupon type now implements real logic — identifies cheapest eligible items as free, with percentage discount applied. Falls back to percentage if metadata not configured.</li></ul><h3 id="model-fixes" tabindex="-1">Model Fixes <a class="header-anchor" href="#model-fixes" aria-label="Permalink to &quot;Model Fixes&quot;">​</a></h3><ul><li>Added <code>dispute</code> to valid transaction types in <code>Transaction</code> model.</li><li>Fixed all <code>Wallet::create</code> duplicates across tests (UserObserver auto-creates wallet on registration).</li><li>Fixed <code>Wishlist::create</code> duplicates across tests (same UserObserver pattern).</li></ul><h3 id="test-improvements" tabindex="-1">Test Improvements <a class="header-anchor" href="#test-improvements" aria-label="Permalink to &quot;Test Improvements&quot;">​</a></h3><ul><li>10 new PaymentService webhook handler tests with real DB data.</li><li>Webhook deduplication, default match branch, and all 6 event types covered.</li><li>URL closure validation tests, SearchController popular endpoint test, ReturnController ORDER_NOT_OWNED branch test.</li><li>PaymentController confirm/retry error branch tests, ShipmentController default status branch test.</li><li>OrderObserver, ShippingCalculator, ProductService sync images tests.</li><li>ReviewController authenticated votes loading fix (<code>actingAs</code> instead of <code>authHeaders</code> on public routes).</li></ul><h3 id="security-audit" tabindex="-1">Security Audit <a class="header-anchor" href="#security-audit" aria-label="Permalink to &quot;Security Audit&quot;">​</a></h3><ul><li>Full security audit completed: no critical vulnerabilities found.</li><li>10 security domains verified (SQL Injection, Mass Assignment, IDOR, Rate Limiting, Input Validation, XSS, File Uploads, Webhook Verification, Sensitive Data, CORS).</li></ul><hr><h2 id="v1-0-1-—-2026-03-13" tabindex="-1">v1.0.1 — 2026-03-13 <a class="header-anchor" href="#v1-0-1-—-2026-03-13" aria-label="Permalink to &quot;v1.0.1 — 2026-03-13&quot;">​</a></h2><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><strong>Order model</strong>: Added <code>returned</code> status to allowed values and DB enum — shipments marked as returned now correctly sync the order status.</li><li><strong>Product model</strong>: Added missing <code>orderItems()</code> relation required by the admin analytics endpoint (<code>top_products</code>).</li><li><strong>WebhookDelivery model</strong>: Added <code>delivered</code> to allowed status values — webhook send success was being blocked by validation.</li><li><strong>CurrencyService</strong>: Fixed column name from <code>rate</code> to <code>exchange_rate</code> in <code>getRate()</code> and <code>syncRates()</code>.</li><li><strong>ProductFilterService</strong>: Fixed <code>in_stock</code> filter — corrected relation name (<code>variants.inventories</code>) and column names (<code>quantity_on_hand</code>, <code>quantity_reserved</code>).</li><li>Increased test coverage from 87.8% to ~98.7% with 86+ new tests.</li></ul><hr><h2 id="v1-0-0-—-2026-03-05" tabindex="-1">v1.0.0 — 2026-03-05 <a class="header-anchor" href="#v1-0-0-—-2026-03-05" aria-label="Permalink to &quot;v1.0.0 — 2026-03-05&quot;">​</a></h2><p>Initial release.</p><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li>300+ REST API endpoints across 25 modules</li><li>87 database tables (68 core + 19 bonus)</li><li>Full Stripe integration — payment intents, 3DS, saved cards, webhooks, refunds, disputes</li><li>Filament v3 admin panel with 46 resources — fully translated to English</li><li>Multi-warehouse inventory management with stock movements</li><li>Loyalty points &amp; gift cards system</li><li>Flash sales, product bundles, price tiers</li><li>Affiliate marketing with conversion tracking</li><li>Customer groups with custom discounts</li><li>Meilisearch full-text search with facets, filters, autocomplete</li><li>18+ email + push notifications (OrderPlaced, Shipped, Refund, Return, Invoice, Welcome, StockAlert, etc.)</li><li>Custom webhook endpoints with delivery logs</li><li>Tax categories &amp; automatic invoice generation</li><li>Multi-language support — EN, FR, AR (RTL), ES, DE</li><li>Multi-currency — USD, EUR, GBP, MAD, CAD, CHF, AED</li><li>Frontend demo — Bootstrap 5 + jQuery + Stripe.js (single HTML file)</li><li>2443 automated tests / 4783 assertions / 100% code coverage</li><li>MinIO / AWS S3 storage for images</li><li>Laravel Horizon for queue monitoring</li><li>Rate limiting &amp; CORS configured</li><li>Spatie Laravel Permission (3 roles, 57 permissions)</li></ul>',21)])])}const m=i(l,[["render",r]]);export{g as __pageData,m as default};
